INSERT INTO programming_language_problems (question, answer, explanation, prog_language, difficulty, question_text) VALUES
('C언어에서 변수를 선언할 때 사용되는 키워드는 _______이며, 이 키워드 뒤에 자료형과 변수명을 작성한다.\n예: _______ int num;', 'int', 'int는 정수형 변수를 선언하는 키워드이다. float는 실수형, char는 문자형 변수를 선언한다.', 'c', 1, 'C언어에서 변수를 선언할 때 사용되는 키워드는 _______이며, 이 키워드 뒤에 자료형과 변수명을 작성한다.\n예: _______ int num;'),
('C언어에서 포인터 변수를 선언할 때 사용하는 기호는 _______이다.\n예: int *ptr;', '*', '포인터는 메모리 주소를 저장하는 변수로, 선언 시 * 기호를 사용한다.', 'c', 2, 'C언어에서 포인터 변수를 선언할 때 사용하는 기호는 _______이다.\n예: int *ptr;'),
('C언어에서 배열의 첫 번째 인덱스는 _______부터 시작한다.\n예: int arr[5]; arr[_____] = 10;', '0', 'C언어를 포함한 대부분의 프로그래밍 언어에서 배열은 0부터 인덱싱된다.', 'c', 1, 'C언어에서 배열의 첫 번째 인덱스는 _______부터 시작한다.\n예: int arr[5]; arr[_____] = 10;'),
('C언어에서 문자를 저장하기 위한 자료형은 _______이며, 작은따옴표로 감싼다.\n예: _______ ch = ''A'';', 'char', 'char는 character의 약자로, 단일 문자를 저장하는 자료형이다.', 'c', 1, 'C언어에서 문자를 저장하기 위한 자료형은 _______이며, 작은따옴표로 감싼다.\n예: _______ ch = ''A'';'),
('C언어에서 표준 입출력 함수는 _______ 헤더 파일에 정의되어 있다.\n예: #include <_____.h>', 'stdio', 'stdio는 Standard Input Output의 약자로, printf, scanf 등 입출력 함수를 사용하려면 이 헤더를 포함해야 한다.', 'c', 2, 'C언어에서 표준 입출력 함수는 _______ 헤더 파일에 정의되어 있다.\n예: #include <_____.h>'),
('C언어에서 동적 메모리 할당을 해제하는 함수는 _______이다.\n예: free(ptr);', 'free', 'malloc, calloc으로 할당한 메모리는 사용 후 반드시 free로 해제해야 메모리 누수가 발생하지 않는다.', 'c', 2, 'C언어에서 동적 메모리 할당을 해제하는 함수는 _______이다.\n예: free(ptr);'),
('C언어에서 문자열을 저장할 때는 _______ 배열을 사용하며, 마지막에 NULL 문자가 추가된다.\n예: _______ str[] = "Hello";', 'char', 'C언어에서 문자열은 char 배열에 저장되며,末尾에 ''\0''(NULL 문자)가 자동으로 추가된다.', 'c', 1, 'C언어에서 문자열을 저장할 때는 _______ 배열을 사용하며, 마지막에 NULL 문자가 추가된다.\n예: _______ str[] = "Hello";'),
('C언어에서 조건문 if의 조건이 참일 때 실행되는 블록은 _______ 로 감싼다.\n예: if (x > 0) _______ printf("양수");', '중괄호 {}', 'if문에서 실행할 코드가 여러 줄이면 중괄호 {}로 감싸야 한다. 한 줄은 생략 가능하다.', 'c', 1, 'C언어에서 조건문 if의 조건이 참일 때 실행되는 블록은 _______ 로 감싼다.\n예: if (x > 0) _______ printf("양수");'),
('C언어에서 반복문 for의 기본 형식은 for(초기화; _______ ; 증감)이다.\n예: for(i=0; i<10; i++)', '조건식', 'for문은 초기화 → 조건식 판단 → 실행 → 증감 순으로 동작한다. 조건식이 거짓이면 반복을 종료한다.', 'c', 1, 'C언어에서 반복문 for의 기본 형식은 for(초기화; _______ ; 증감)이다.\n예: for(i=0; i<10; i++)'),
('C언어에서 함수의 반환값이 없을 때 사용하는 자료형은 _______ 이다.\n예: _______ printHello(void);', 'void', 'void는 "비어 있음"을 의미하며, 반환값이 없거나 매개변수가 없음을 나타낸다.', 'c', 1, 'C언어에서 함수의 반환값이 없을 때 사용하는 자료형은 _______ 이다.\n예: _______ printHello(void);'),
('C언어에서 구조체를 정의할 때 사용하는 키워드는 _______ 이다.\n예: _______ Student { char name[20]; int age; };', 'struct', 'struct는 서로 관련된 변수들을 그룹화하는 사용자 정의 자료형이다.', 'c', 2, 'C언어에서 구조체를 정의할 때 사용하는 키워드는 _______ 이다.\n예: _______ Student { char name[20]; int age; };'),
('C언어에서 파일 포인터를 선언할 때 사용하는 자료형은 _______ 이다.\n예: _______ *fp = fopen("test.txt", "r");', 'FILE', 'FILE은 stdio.h에 정의된 구조체로, 파일의 정보와 버퍼를 관리한다.', 'c', 2, 'C언어에서 파일 포인터를 선언할 때 사용하는 자료형은 _______ 이다.\n예: _______ *fp = fopen("test.txt", "r");'),
('C언어에서 두 변수의 값을 교환하려면 _______ 변수를 사용한다.\n예: int temp = a; a = b; b = _______;', '임시(temp)', '값을 교환하려면 임시 변수에 한 쪽 값을 저장해두어야 한다.', 'c', 1, 'C언어에서 두 변수의 값을 교환하려면 _______ 변수를 사용한다.\n예: int temp = a; a = b; b = _______;'),
('C언어에서 문자열의 길이를 구하는 함수는 _______ 이다.\n예: int len = strlen("Hello");', 'strlen', 'strlen은 string.h에 정의되어 있으며, NULL 문자를 제외한 문자 수를 반환한다.', 'c', 1, 'C언어에서 문자열의 길이를 구하는 함수는 _______ 이다.\n예: int len = strlen("Hello");'),
('C언어에서 메모리 주소를 출력할 때 사용하는 서식 지정자는 _______ 이다.\n예: printf("주소: %p", &num);', '%p', '%p는 포인터의 주소값을 16진수로 출력한다. &는 변수의 주소를 얻는 연산자이다.', 'c', 2, 'C언어에서 메모리 주소를 출력할 때 사용하는 서식 지정자는 _______ 이다.\n예: printf("주소: %p", &num);'),
('C언어에서 switch문에서 case에 해당하지 않는 경우 실행되는 부분은 _______ 이다.\n예: switch(x) { case 1: ...; _______: ...; }', 'default', 'default는 어떤 case에도 해당하지 않을 때 실행된다. 생략 가능하다.', 'c', 1, 'C언어에서 switch문에서 case에 해당하지 않는 경우 실행되는 부분은 _______ 이다.\n예: switch(x) { case 1: ...; _______: ...; }'),
('C언어에서 동적 메모리 할당을 하는 함수는 _______ 이다.\n예: int *arr = malloc(10 * sizeof(int));', 'malloc', 'malloc은 heap 영역에 지정한 크기만큼의 메모리를 할당한다. 반환값은 void* 포인터이다.', 'c', 2, 'C언어에서 동적 메모리 할당을 하는 함수는 _______ 이다.\n예: int *arr = malloc(10 * sizeof(int));'),
('C언어에서 do-while문과 while문의 차이점은 _______ 이다.\ndo-while은 조건을 나중에 확인하므로 최소 1회 실행된다.', '실행 순서', 'while은 조건을 먼저 확인하고, do-while은 본문을 먼저 실행한 후 조건을 확인한다.', 'c', 2, 'C언어에서 do-while문과 while문의 차이점은 _______ 이다.\ndo-while은 조건을 나중에 확인하므로 최소 1회 실행된다.'),
('C언어에서 전처리기 지시어는 _______ 기호로 시작한다.\n예: _______ include <stdio.h>', '#', '#으로 시작하는 지시어는 컴파일 전에 전처리기에 의해 처리된다. #define, #include, #ifdef 등이 있다.', 'c', 1, 'C언어에서 전처리기 지시어는 _______ 기호로 시작한다.\n예: _______ include <stdio.h>'),
('C언어에서 상수를 정의할 때 사용하는 전처리기 지시어는 _______ 이다.\n예: _______ PI 3.14159', '#define', '#define은 매크로를 정의한다. PI를 3.14159로 치환된다. enum도 상수 정의에 사용된다.', 'c', 1, 'C언어에서 상수를 정의할 때 사용하는 전처리기 지시어는 _______ 이다.\n예: _______ PI 3.14159'),
('C언어에서 구조체 변수의 멤버에 접근할 때 사용하는 연산자는 _______ 이다.\n예: struct Student s; s______name = "Kim";', '.', '구조체 변수의 멤버 접근은 .(dot) 연산자를 사용한다. 포인터에서는 -> 연산자를 사용한다.', 'c', 1, 'C언어에서 구조체 변수의 멤버에 접근할 때 사용하는 연산자는 _______ 이다.\n예: struct Student s; s______name = "Kim";'),
('C언어에서 break문은 _______ 또는 switch문에서만 사용할 수 있다.\n중첩 반복문에서 특정 레벨만 탈출할 때 사용한다.', '반복문', 'break는 for, while, do-while, switch에서 사용 가능하다. continue는 현재 반복만 건너뛴다.', 'c', 1, 'C언어에서 break문은 _______ 또는 switch문에서만 사용할 수 있다.\n중첩 반복문에서 특정 레벨만 탈출할 때 사용한다.'),
('C언어에서 포인터가 아무것도 가리키지 않을 때 대입하는 값은 _______ 이다.\n예: int *ptr = NULL;', 'NULL', 'NULL은 0으로 정의된 매크로로, 포인터가 유효한 주소를 가리키지 않음을 나타낸다.', 'c', 1, 'C언어에서 포인터가 아무것도 가리키지 않을 때 대입하는 값은 _______ 이다.\n예: int *ptr = NULL;'),
('C언어에서 두 문자열을 연결하는 함수는 _______ 이다.\n예: strcat(str1, str2);', 'strcat', 'strcat은 string.h의 함수로, str2를 str1 끝에 붙인다. str1의 NULL 문자 위치에 str2가 복사된다.', 'c', 2, 'C언어에서 두 문자열을 연결하는 함수는 _______ 이다.\n예: strcat(str1, str2);'),
('C언어에서 비트 연산 AND는 _______ 연산자를 사용한다.\n예: int result = a & b;', '&', '&는 비트 AND, &&는 논리 AND이다. 비트 AND는 각 비트가 모두 1일 때 1을 반환한다.', 'c', 2, 'C언어에서 비트 연산 AND는 _______ 연산자를 사용한다.\n예: int result = a & b;'),
('C언어에서 배열을 함수에 전달할 때 실제 전달되는 것은 _______ 이다.\n배열의 이름은 첫 번째 요소의 주소를 의미한다.', '포인터', 'C에서 배열은 함수에 포인터로 전달된다. 배열의 크기는 별도로 매개변수로 전달해야 한다.', 'c', 2, 'C언어에서 배열을 함수에 전달할 때 실제 전달되는 것은 _______ 이다.\n배열의 이름은 첫 번째 요소의 주소를 의미한다.'),
('C언어에서 enum은 _______ 상수를 정의할 때 사용한다.\n예: enum Color { RED, GREEN, BLUE };', '열거형', 'enum은 정수 상수에 이름을 부여한다. 기본적으로 0부터 시작하여 1씩 증가한다.', 'c', 2, 'C언어에서 enum은 _______ 상수를 정의할 때 사용한다.\n예: enum Color { RED, GREEN, BLUE };'),
('C언어에서 typedef는 기존 자료형에 _______ 을(를) 부여할 때 사용한다.\n예: typedef unsigned long ulong;', '별칭', 'typedef는 복잡한 자료형 선언을 간결하게 만든다. struct, 포인터 등에도 사용 가능하다.', 'c', 2, 'C언어에서 typedef는 기존 자료형에 _______ 을(를) 부여할 때 사용한다.\n예: typedef unsigned long ulong;'),
('C언어에서 정수형 변수의 크기를 구하는 연산자는 _______ 이다.\n예: printf("%zu", sizeof(int));', 'sizeof', 'sizeof는 자료형이나 변수의 바이트 수를 반환한다. 결과는 size_t(unsigned) 타입이다.', 'c', 1, 'C언어에서 정수형 변수의 크기를 구하는 연산자는 _______ 이다.\n예: printf("%zu", sizeof(int));'),
('C언어에서 파일 읽기 함수 _______ 은(는) 한 줄씩 문자열을 읽는다.\n예: fgets(buffer, 100, fp);', 'fgets', 'fgets는 지정된 크기까지 한 줄을 읽는다. 개행 문자도 포함된다. EOF에서 NULL을 반환한다.', 'c', 2, 'C언어에서 파일 읽기 함수 _______ 은(는) 한 줄씩 문자열을 읽는다.\n예: fgets(buffer, 100, fp);'),
('C언어에서 삼항 연산자의 형식은 조건 ? _______ : 거짓값 이다.\n예: int max = (a > b) ? a : b;', '참값', '삼항 연산자는 if-else를 간결하게 표현한다. 조건이 참이면 참값, 거짓이면 거짓값이 반환된다.', 'c', 1, 'C언어에서 삼항 연산자의 형식은 조건 ? _______ : 거짓값 이다.\n예: int max = (a > b) ? a : b;'),
('C언어에서 auto, static, extern은 _______ 지정자이다.\n이 중 _______ 는 함수가 종료되어도 값이 유지된다.', '저장 클래스', 'auto는 지역 변수 기본값, static은 값 유지, extern은 외부 링크, register는 CPU 레지스터에 보관한다.', 'c', 3, 'C언어에서 auto, static, extern은 _______ 지정자이다.\n이 중 _______ 는 함수가 종료되어도 값이 유지된다.'),
('C언어에서 구조체 포인터로 멤버에 접근할 때 사용하는 연산자는 _______ 이다.\n예: struct Student *p = &s; p______name;', '-> (화살표)', '->는 구조체 포인터로 멤버에 접근할 때 사용한다. (*p).name 과 동일하다.', 'c', 2, 'C언어에서 구조체 포인터로 멤버에 접근할 때 사용하는 연산자는 _______ 이다.\n예: struct Student *p = &s; p______name;'),
('C언어에서 continue문은 반복문에서 나머지 코드를 건너뛰고 _______ 로 이동한다.\nbreak문은 반복문을 완전히 탈출한다.', '다음 반복', 'continue는 현재 반복의 나머지 부분을 건너뛰고 증감식과 조건 판단으로 이동한다.', 'c', 1, 'C언어에서 continue문은 반복문에서 나머지 코드를 건너뛰고 _______ 로 이동한다.\nbreak문은 반복문을 완전히 탈출한다.');
INSERT INTO programming_language_problems (question, answer, explanation, prog_language, difficulty, question_text) VALUES
('Java에서 클래스의 인스턴스를 생성할 때 사용하는 키워드는 _______ 이다.\n예: MyClass obj = _______ MyClass();', 'new', 'new는 heap 영역에 객체 메모리를 할당하고 생성자를 호출한다.', 'java', 1, 'Java에서 클래스의 인스턴스를 생성할 때 사용하는 키워드는 _______ 이다.\n예: MyClass obj = _______ MyClass();'),
('Java에서 객체의 자료형을 확인하는 키워드는 _______ 이다.\n예: if (obj _______ String) { ... }', 'instanceof', 'instanceof는 객체가 특정 클래스 또는 인터페이스의 인스턴스인지 확인한다.', 'java', 2, 'Java에서 객체의 자료형을 확인하는 키워드는 _______ 이다.\n예: if (obj _______ String) { ... }'),
('Java에서 main 메서드의 반환 자료형은 _______ 이다.\n예: public _______ main(String[] args) {}', 'void', 'main 메서드는 반환값이 없어야 한다. static 메서드로 JVM에 의해 직접 호출된다.', 'java', 1, 'Java에서 main 메서드의 반환 자료형은 _______ 이다.\n예: public _______ main(String[] args) {}'),
('Java에서 문자열을 비교할 때 == 대신 _______ 메서드를 사용해야 한다.\n==는 참조 주소를 비교한다.', 'equals', 'equals는 문자열의 내용을 비교한다. ==는 객체 참조(주소)를 비교하므로 예상과 다른 결과가 나올 수 있다.', 'java', 2, 'Java에서 문자열을 비교할 때 == 대신 _______ 메서드를 사용해야 한다.\n==는 참조 주소를 비교한다.'),
('Java에서 예외를 처리하기 위해 try 블록 뒤에 사용하는 키워드는 _______ 이다.\n예: try { ... } _______ (Exception e) { ... }', 'catch', 'catch는 try 블록에서 발생한 예외를 처리한다. finally 블록은 선택적으로 항상 실행된다.', 'java', 1, 'Java에서 예외를 처리하기 위해 try 블록 뒤에 사용하는 키워드는 _______ 이다.\n예: try { ... } _______ (Exception e) { ... }'),
('Java에서 상속을 받을 때 사용하는 키워드는 _______ 이다.\n예: class Child _______ Parent { }', 'extends', 'extends는 클래스 상속, implements는 인터페이스 구현에 사용한다. Java는 단일 상속만 지원한다.', 'java', 1, 'Java에서 상속을 받을 때 사용하는 키워드는 _______ 이다.\n예: class Child _______ Parent { }'),
('Java에서 인터페이스를 구현할 때 사용하는 키워드는 _______ 이다.\n예: class MyClass _______ MyInterface { }', 'implements', 'implements로 인터페이스를 구현하면 모든 추상 메서드를 오버라이딩해야 한다.', 'java', 1, 'Java에서 인터페이스를 구현할 때 사용하는 키워드는 _______ 이다.\n예: class MyClass _______ MyInterface { }'),
('Java에서 부모 클래스의 생성자를 호출할 때 사용하는 키워드는 _______ 이다.\n예: _______ (name);', 'super', 'super는 부모 클래스의 생성자 또는 메서드를 호출한다. this는 현재 클래스의 것을 호출한다.', 'java', 1, 'Java에서 부모 클래스의 생성자를 호출할 때 사용하는 키워드는 _______ 이다.\n예: _______ (name);'),
('Java에서 정적 메서드는 _______ 키워드로 선언한다.\n이 메서드는 인스턴스 생성 없이 클래스명으로 호출 가능하다.', 'static', 'static 메서드는 객체 생성 없이 Class.method() 형태로 호출된다. 인스턴스 변수에 접근할 수 없다.', 'java', 1, 'Java에서 정적 메서드는 _______ 키워드로 선언한다.\n이 메서드는 인스턴스 생성 없이 클래스명으로 호출 가능하다.'),
('Java에서 상속을 제한하거나 변경을 방지할 때 사용하는 키워드는 _______ 이다.\n이 클래스는 상속받을 수 없다.', 'final', 'final 클래스는 상속 불가, final 메서드는 오버라이딩 불가, final 변수는 상수이다.', 'java', 2, 'Java에서 상속을 제한하거나 변경을 방지할 때 사용하는 키워드는 _______ 이다.\n이 클래스는 상속받을 수 없다.'),
('Java에서 동적 다형성을 구현하는 메서드 오버라이딩의 핵심은 _______ 이다.\n하위 클래스가 상위 클래스의 메서드를 재정의한다.', '오버라이딩', '오버라이딩은 실행 시점에 실제 객체 타입의 메서드를 호출한다. 컴파일 시점 타입과 다를 수 있다.', 'java', 2, 'Java에서 동적 다형성을 구현하는 메서드 오버라이딩의 핵심은 _______ 이다.\n하위 클래스가 상위 클래스의 메서드를 재정의한다.'),
('Java에서 컬렉션 프레임워크의 리스트 구현체 중 동기화를 지원하는 것은 _______ 이다.\n이 클래스는 멀티스레드 환경에서 안전하다.', 'Vector', 'Vector는 synchronized로 동기화되어 있다. ArrayList는 동기화가 안 되어 빠르지만 스레드 안전하지 않다.', 'java', 2, 'Java에서 컬렉션 프레임워크의 리스트 구현체 중 동기화를 지원하는 것은 _______ 이다.\n이 클래스는 멀티스레드 환경에서 안전하다.'),
('Java에서 문자열이 불변 객체임을 나타내기 위해 사용하는 클래스는 _______ 이다.\n한 번 생성되면 내용을 변경할 수 없다.', 'String', 'String은 immutable이다. 변경 시 새 객체가 생성된다. 가변 문자열은 StringBuilder, StringBuffer를 사용한다.', 'java', 2, 'Java에서 문자열이 불변 객체임을 나타내기 위해 사용하는 클래스는 _______ 이다.\n한 번 생성되면 내용을 변경할 수 없다.'),
('Java에서 쓰레드를 생성하는 두 가지 방법은 Thread 클래스 상속과 _______ 인터페이스 구현이다.', 'Runnable', 'Runnable 인터페이스는 run() 메서드만 구현하면 된다. 다중 상속이 가능하므로 더 유연하다.', 'java', 2, 'Java에서 쓰레드를 생성하는 두 가지 방법은 Thread 클래스 상속과 _______ 인터페이스 구현이다.'),
('Java에서 예외를 강제로 발생시킬 때 사용하는 키워드는 _______ 이다.\n예: _______ new IllegalArgumentException("잘못된 값");', 'throw', 'throw는 예외 객체를 발생시킨다. throws는 메서드 선언부에서 발생 가능한 예외를 명시한다.', 'java', 1, 'Java에서 예외를 강제로 발생시킬 때 사용하는 키워드는 _______ 이다.\n예: _______ new IllegalArgumentException("잘못된 값");'),
('Java에서 제네릭의 유형 매개변수 T는 _______ 를 의미한다.\n컴파일 시점에 실제 유형으로 대체된다.', 'Type', '제네릭의 관례: T(Type), E(Element), K(Key), V(Value), N(Number). 유형 안전성을 보장한다.', 'java', 2, 'Java에서 제네릭의 유형 매개변수 T는 _______ 를 의미한다.\n컴파일 시점에 실제 유형으로 대체된다.'),
('Java에서 입력 스트림의 최상위 클래스는 _______ 이다.\n바이트 기반 입출력을 처리한다.', 'InputStream', 'InputStream은 바이트 기반, Reader는 문자 기반이다. FileInputStream, BufferedInputStream 등이 있다.', 'java', 2, 'Java에서 입력 스트림의 최상위 클래스는 _______ 이다.\n바이트 기반 입출력을 처리한다.'),
('Java에서 객체를 문자열로 변환하는 메서드는 _______ 이다.\n모든 객체가 이 메서드를 가진다.', 'toString', 'toString()은 Object 클래스에 정의되어 있다. 오버라이딩하여 객체의 유용한 정보를 반환하도록 할 수 있다.', 'java', 1, 'Java에서 객체를 문자열로 변환하는 메서드는 _______ 이다.\n모든 객체가 이 메서드를 가진다.'),
('Java에서 두 객체의 내용이 같은지 비교하는 메서드는 _______ 이다.\n이 메서드를 오버라이딩할 때는 hashCode도 함께 오버라이딩해야 한다.', 'equals', 'equals는 내용 비교, ==는 참조 비교이다. HashSet, HashMap 사용 시 equals와 hashCode를 함께 오버라이딩해야 한다.', 'java', 2, 'Java에서 두 객체의 내용이 같은지 비교하는 메서드는 _______ 이다.\n이 메서드를 오버라이딩할 때는 hashCode도 함께 오버라이딩해야 한다.'),
('Java에서 인터페이스의 모든 메서드는 기본적으로 _______ 이다.\nJava 8부터는 default 메서드도 지원한다.', 'public abstract', '인터페이스의 메서드는 명시하지 않아도 public abstract이다. Java 8부터 default, static 메서드도 허용한다.', 'java', 2, 'Java에서 인터페이스의 모든 메서드는 기본적으로 _______ 이다.\nJava 8부터는 default 메서드도 지원한다.'),
('Java에서 ArrayList의 기본 초기 용량은 _______ 이다.\n데이터가 가득 차면 약 1.5배로 자동 확장된다.', '10', 'ArrayList는 처음에 10개의 슬롯을 생성한다. 추가 시 grow() 메서드로 내부 배열을 확장한다.', 'java', 2, 'Java에서 ArrayList의 기본 초기 용량은 _______ 이다.\n데이터가 가득 차면 약 1.5배로 자동 확장된다.'),
('Java에서 HashMap의 키로 사용할 수 없는 것은 _______ 값이다.\nnull 키는 허용되지만, 중복 키는 덮어씌워진다.', '중복된', 'HashMap은 키의 hashCode로 버킷을 결정한다. equals로 동등성을 확인한다. 중복 키는 마지막 값으로 덮어씌워진다.', 'java', 2, 'Java에서 HashMap의 키로 사용할 수 없는 것은 _______ 값이다.\nnull 키는 허용되지만, 중복 키는 덮어씌워진다.'),
('Java에서 람다 표현식을 사용할 수 있는 인터페이스는 _______ 인터페이스이다.\n단 하나의 추상 메서드만 가진다.', '함수형', '함수형 인터페이스는 @FunctionalInterface 어노테이션으로 표시한다. Supplier, Consumer, Function 등이 있다.', 'java', 2, 'Java에서 람다 표현식을 사용할 수 있는 인터페이스는 _______ 인터페이스이다.\n단 하나의 추상 메서드만 가진다.'),
('Java에서 try-with-resources 문을 사용하면 자원을 자동으로 _______ 한다.\nAutoCloseable 인터페이스를 구현한 클래스만 사용 가능하다.', '닫기(close)', 'try-with-resources는 try 블록이 끝나면 자동으로 close()를 호출한다. 자원 누수를 방지한다.', 'java', 2, 'Java에서 try-with-resources 문을 사용하면 자원을 자동으로 _______ 한다.\nAutoCloseable 인터페이스를 구현한 클래스만 사용 가능하다.'),
('Java에서 쓰레드의 우선순위를 변경하는 메서드는 _______ 이다.\n우선순위가 높은 쓰레드가 더 많이 실행된다.', 'setPriority', 'setPriority(1~10)로 우선순위를 설정한다. 하지만 OS 스케줄링에 따라 보장이 안 될 수 있다.', 'java', 3, 'Java에서 쓰레드의 우선순위를 변경하는 메서드는 _______ 이다.\n우선순위가 높은 쓰레드가 더 많이 실행된다.'),
('Java에서 추상 클래스는 _______ 키워드로 선언한다.\n이 클래스는 직접 인스턴스를 생성할 수 없다.', 'abstract', 'abstract 클래스는 추상 메서드를 가질 수 있으며, 상속받아 구현해야 한다. new로 인스턴스 생성 불가.', 'java', 1, 'Java에서 추상 클래스는 _______ 키워드로 선언한다.\n이 클래스는 직접 인스턴스를 생성할 수 없다.'),
('Java에서 열거형 상수를 정의할 때 사용하는 키워드는 _______ 이다.\n예: _______ Season { SPRING, SUMMER, FALL, WINTER }', 'enum', 'enum은 타입 안전한 상수를 정의한다. switch문과 함께 사용하면 유용하다. 메서드와 필드도 가질 수 있다.', 'java', 1, 'Java에서 열거형 상수를 정의할 때 사용하는 키워드는 _______ 이다.\n예: _______ Season { SPRING, SUMMER, FALL, WINTER }'),
('Java에서 자동 언박싱(Auto-Unboxing)이 지원하는 JDK 버전은 _______ 부터이다.\nWrapper 클래스와 기본 자료형 간 자동 변환이 된다.', '5', 'Java 5부터 오토박싱/언박싱을 지원한다. Integer → int 자동 변환이 된다.', 'java', 2, 'Java에서 자동 언박싱(Auto-Unboxing)이 지원하는 JDK 버전은 _______ 부터이다.\nWrapper 클래스와 기본 자료형 간 자동 변환이 된다.'),
('Java에서 패키지를 가져올 때 사용하는 키워드는 _______ 이다.\n예: _______ java.util.ArrayList;', 'import', 'import는 다른 패키지의 클래스를 현재 파일에서 사용할 수 있게 한다. *로 전체 가져오기도 가능하다.', 'java', 1, 'Java에서 패키지를 가져올 때 사용하는 키워드는 _______ 이다.\n예: _______ java.util.ArrayList;'),
('Java에서 synchronized 키워드는 쓰레드의 _______ 을(를) 보장한다.\n한 번에 하나의 쓰레드만 임계 영역에 진입할 수 있다.', '동기화', 'synchronized는 메서드 또는 블록에 적용 가능하다. 락을 획득한 쓰레드만 실행하고, 나머지는 대기한다.', 'java', 3, 'Java에서 synchronized 키워드는 쓰레드의 _______ 을(를) 보장한다.\n한 번에 하나의 쓰레드만 임계 영역에 진입할 수 있다.'),
('Java에서 String을 반복해서 변경할 때 효율적인 클래스는 _______ 이다.\n이 클래스는 가변 문자열을 지원한다.', 'StringBuilder', 'StringBuilder는 스레드 안전하지 않지만 빠르다. StringBuffer는 스레드 안전하지만 느리다.', 'java', 2, 'Java에서 String을 반복해서 변경할 때 효율적인 클래스는 _______ 이다.\n이 클래스는 가변 문자열을 지원한다.'),
('Java에서 접근 제어자 중 같은 패키지 내에서만 접근 가능한 것은 _______ 이다.\n클래스 멤버에 적용할 수 있다.', 'default(package-private)', '접근 제어자: public(전체), protected(패키지+상속), default(패키지), private(클래스 내부).', 'java', 2, 'Java에서 접근 제어자 중 같은 패키지 내에서만 접근 가능한 것은 _______ 이다.\n클래스 멤버에 적용할 수 있다.'),
('Java에서 Stream API의 최종 연산으로 컬렉션을 반환하는 메서드는 _______ 이다.\n중간 연산(filter, map) 후에 결과를 수집한다.', 'collect', 'collect는 Collectors 클래스와 함께 사용된다. toList(), toMap(), groupingBy() 등이 있다.', 'java', 3, 'Java에서 Stream API의 최종 연산으로 컬렉션을 반환하는 메서드는 _______ 이다.\n중간 연산(filter, map) 후에 결과를 수집한다.');
INSERT INTO programming_language_problems (question, answer, explanation, prog_language, difficulty, question_text) VALUES
('Python에서 변수에 값을 할당할 때 사용하는 기호는 _______ 이다.\n예: x _______ 10', '=', '=는 대입 연산자이다. ==는 비교 연산자이므로 혼동하지 않아야 한다.', 'python', 1, 'Python에서 변수에 값을 할당할 때 사용하는 기호는 _______ 이다.\n예: x _______ 10'),
('Python에서 주석을 작성할 때 사용하는 기호는 _______ 이다.\n예: _______ 이것은 주석입니다', '#', '# 뒤의 내용은 파이썬 인터프리터가 무시한다. 여러 줄 주석은 따옴표 3개를 사용한다.', 'python', 1, 'Python에서 주석을 작성할 때 사용하는 기호는 _______ 이다.\n예: _______ 이것은 주석입니다'),
('Python에서 리스트의 길이를 구하는 함수는 _______ 이다.\n예: _______ [1, 2, 3]  # 결과: 3', 'len', 'len()은 리스트, 튜플, 문자열, 딕셔너리 등 시퀀스의 길이를 반환한다.', 'python', 1, 'Python에서 리스트의 길이를 구하는 함수는 _______ 이다.\n예: _______ [1, 2, 3]  # 결과: 3'),
('Python에서 조건문 if의 들여쓰기는 보통 공백 _______ 개를 사용한다.\n예: if x > 0:\n    print("양수")', '4', 'Python은 들여쓰기로 블록을 구분한다. PEP 8 표준은 공백 4개를 권장한다. 탭과 공백을 혼용하면 오류가 발생한다.', 'python', 1, 'Python에서 조건문 if의 들여쓰기는 보통 공백 _______ 개를 사용한다.\n예: if x > 0:\n    print("양수")'),
('Python에서 함수를 정의할 때 사용하는 키워드는 _______ 이다.\n예: _______ greet(name):\n    print(f"Hello, {name}")', 'def', 'def는 function의 약자이다. 매개변수와 반환값은 선택적이다.', 'python', 1, 'Python에서 함수를 정의할 때 사용하는 키워드는 _______ 이다.\n예: _______ greet(name):\n    print(f"Hello, {name}")'),
('Python에서 리스트에 요소를 추가하는 메서드는 _______ 이다.\n예: lst.append(4)', 'append', 'append는 리스트 끝에 요소를 하나 추가한다. extend는 여러 요소를 한 번에 추가한다.', 'python', 1, 'Python에서 리스트에 요소를 추가하는 메서드는 _______ 이다.\n예: lst.append(4)'),
('Python에서 문자열의 모든 문자를 대문자로 변환하는 메서드는 _______ 이다.\n예: "hello".______ ()  # 결과: "HELLO"', 'upper', 'upper()는 대문자로, lower()는 소문자로 변환한다. isupper(), islower()는 판별 메서드이다.', 'python', 1, 'Python에서 문자열의 모든 문자를 대문자로 변환하는 메서드는 _______ 이다.\n예: "hello".______ ()  # 결과: "HELLO"'),
('Python에서 예외를 처리할 때 try 블록 뒤에 사용하는 키워드는 _______ 이다.\n예: try:\n    1/0\n______  ZeroDivisionError:\n    print("0으로 나눌 수 없습니다")', 'except', 'except는 발생한 예외의 유형에 따라 다르게 처리할 수 있다. finally는 항상 실행된다.', 'python', 1, 'Python에서 예외를 처리할 때 try 블록 뒤에 사용하는 키워드는 _______ 이다.\n예: try:\n    1/0\n______  ZeroDivisionError:\n    print("0으로 나눌 수 없습니다")'),
('Python에서 키-값 쌍을 저장하는 자료형은 _______ 이다.\n예: _______  = {"name": "Kim", "age": 30}', '딕셔너리(dict)', '딕셔너리는 {키: 값} 쌍을 저장한다. 키는 불변 객체만 사용 가능하다. 해시 테이블로 구현되어 있다.', 'python', 1, 'Python에서 키-값 쌍을 저장하는 자료형은 _______ 이다.\n예: _______  = {"name": "Kim", "age": 30}'),
('Python에서 파일 객체를 자동으로 닫아주는 구문은 _______ 문이다.\n예: _______  open("test.txt") as f:\n    data = f.read()', 'with', 'with 문은 블록을 벗어나면 자동으로 close()를 호출한다. 자원 관리에 편리하다.', 'python', 1, 'Python에서 파일 객체를 자동으로 닫아주는 구문은 _______ 문이다.\n예: _______  open("test.txt") as f:\n    data = f.read()'),
('Python에서 리스트의 요소를 반복 처리하는 구문은 _______ 문이다.\n예: _______  item in [1, 2, 3]:\n    print(item)', 'for', 'for ... in ... 구문은 시퀀스의 각 요소를 순회한다. range()와 함께 사용하기도 한다.', 'python', 1, 'Python에서 리스트의 요소를 반복 처리하는 구문은 _______ 문이다.\n예: _______  item in [1, 2, 3]:\n    print(item)'),
('Python에서 None은 _______ 을(를) 의미한다.\n값이 없음을 나타내는 상수이다.', '널(null)', 'None은 Python의 singleton 객체이다. 변수에 값이 없음을 명시할 때 사용한다. is None으로 비교한다.', 'python', 1, 'Python에서 None은 _______ 을(를) 의미한다.\n값이 없음을 나타내는 상수이다.'),
('Python에서 객체의 자료형을 확인하는 함수는 _______ 이다.\n예: _______ (42)  # 결과: <class ''int''>', 'type', 'type()은 객체의 클래스를 반환한다. isinstance()는 특정 클래스의 인스턴스인지 확인한다.', 'python', 1, 'Python에서 객체의 자료형을 확인하는 함수는 _______ 이다.\n예: _______ (42)  # 결과: <class ''int''>'),
('Python에서 리스트 컴프리헨션의 기본 형식은 [식 for 변수 in 범위]이다.\n예: [x**2 for x in range(5)]\n결과는 _______ 이다.', '[0, 1, 4, 9, 16]', '리스트 컴프리헨션은 간결하게 리스트를 생성한다. 조건부 필터링도 가능하다: [x for x in range(10) if x%2==0].', 'python', 2, 'Python에서 리스트 컴프리헨션의 기본 형식은 [식 for 변수 in 범위]이다.\n예: [x**2 for x in range(5)]\n결과는 _______ 이다.'),
('Python에서 클래스를 정의할 때 사용하는 키워드는 _______ 이다.\n예: _______  Person:\n    def __init__(self, name):\n        self.name = name', 'class', 'class 키워드로 클래스를 정의한다. __init__은 생성자, self는 인스턴스自身을 참조한다.', 'python', 1, 'Python에서 클래스를 정의할 때 사용하는 키워드는 _______ 이다.\n예: _______  Person:\n    def __init__(self, name):\n        self.name = name'),
('Python에서 상속을 받을 때 괄호 안에 _______ 을(를) 지정한다.\n예: class Child(Parent):', '부모 클래스명', 'Python은 다중 상속을 지원한다: class Child(Parent1, Parent2). MRO(Method Resolution Order)로 메서드를 탐색한다.', 'python', 1, 'Python에서 상속을 받을 때 괄호 안에 _______ 을(를) 지정한다.\n예: class Child(Parent):'),
('Python에서 문자열을 포맷팅할 때 f-string은 _______ 로 시작한다.\n예: _______ "Hello, {name}"', 'f', 'f-string(Python 3.6+)은 문자열 앞에 f를 붙여 {} 안에 변수를 직접 삽입한다. 가장 빠르고 가독성이 좋다.', 'python', 1, 'Python에서 문자열을 포맷팅할 때 f-string은 _______ 로 시작한다.\n예: _______ "Hello, {name}"'),
('Python에서 리스트의 첫 번째 요소를 제거하는 메서드는 _______ 이다.\n예: lst.pop(0)', 'pop', 'pop(index)는 지정된 인덱스의 요소를 제거하고 반환한다. 인자 없으면 마지막 요소를 제거한다.', 'python', 1, 'Python에서 리스트의 첫 번째 요소를 제거하는 메서드는 _______ 이다.\n예: lst.pop(0)'),
('Python에서 두 값을 동시에 교환하는 방식은 _______ 을(를) 사용한다.\n예: a, b = b, a', '튜플 언패킹', 'Python은 임시 변수 없이 튜플로 값을 교환한다. 다중 대입, 함수 반환값 받기 등에도 사용한다.', 'python', 1, 'Python에서 두 값을 동시에 교환하는 방식은 _______ 을(를) 사용한다.\n예: a, b = b, a'),
('Python에서 람다 함수를 정의할 때 사용하는 키워드는 _______ 이다.\n예: square = _______  x: x ** 2', 'lambda', 'lambda는 한 줄 익명 함수이다. 여러 표현식을 사용할 수 없다. map, filter, sorted와 함께 자주 사용된다.', 'python', 2, 'Python에서 람다 함수를 정의할 때 사용하는 키워드는 _______ 이다.\n예: square = _______  x: x ** 2'),
('Python에서 모듈을 가져올 때 사용하는 키워드는 _______ 이다.\n예: _______  math', 'import', 'import는 모듈 전체를 가져온다. from ... import ...는 특정 객체만 가져온다. as로 별칭을 부여할 수 있다.', 'python', 1, 'Python에서 모듈을 가져올 때 사용하는 키워드는 _______ 이다.\n예: _______  math'),
('Python에서 가변 인자를 받을 때 사용하는 기호는 _______ 이다.\n예: def func(*args, **kwargs)', '*', '*args는 위치 인자를 튜플로, **kwargs는 키워드 인자를 딕셔너리로 받는다.', 'python', 2, 'Python에서 가변 인자를 받을 때 사용하는 기호는 _______ 이다.\n예: def func(*args, **kwargs)'),
('Python에서 리스트의 특정 값을 찾아 제거하는 메서드는 _______ 이다.\n예: lst.remove(3)', 'remove', 'remove는 첫 번째로 일치하는 값만 제거한다. 값이 없으면 ValueError가 발생한다.', 'python', 1, 'Python에서 리스트의 특정 값을 찾아 제거하는 메서드는 _______ 이다.\n예: lst.remove(3)'),
('Python에서 딕셔너리의 모든 키를 반환하는 메서드는 _______ 이다.\n예: keys = d.______ ()', 'keys', 'keys()는 딕셔너리 키의 뷰를 반환한다. values()는 값, items()는 키-값 튜플을 반환한다.', 'python', 1, 'Python에서 딕셔너리의 모든 키를 반환하는 메서드는 _______ 이다.\n예: keys = d.______ ()'),
('Python에서 문자열을 특정 기준으로 분할하는 메서드는 _______ 이다.\n예: "a,b,c".______ (",")  # 결과: [''a'', ''b'', ''c'']', 'split', 'split()은 문자열을 분리하여 리스트를 반환한다. 인자 없으면 공백 기준으로 분할한다.', 'python', 1, 'Python에서 문자열을 특정 기준으로 분할하는 메서드는 _______ 이다.\n예: "a,b,c".______ (",")  # 결과: [''a'', ''b'', ''c'']'),
('Python에서 리스트를 역순으로 순회하는 함수는 _______ 이다.\n예: for item in _______ (lst):', 'reversed', 'reversed()는 역방향 이터레이터를 반환한다. 원본 리스트는 변경되지 않는다. sorted()의 reverse=True도 있다.', 'python', 1, 'Python에서 리스트를 역순으로 순회하는 함수는 _______ 이다.\n예: for item in _______ (lst):'),
('Python에서デ코레이터를 정의할 때 사용하는 기호는 _______ 이다.\n예: @my_decorator\ndef func():', '@', '@으로 시작하는 데코레이터는 함수를 감싸는 래퍼 함수이다. @staticmethod, @classmethod 등이 있다.', 'python', 2, 'Python에서デ코레이터를 정의할 때 사용하는 기호는 _______ 이다.\n예: @my_decorator\ndef func():'),
('Python에서 try 블록에서 예외가 발생하지 않아도 항상 실행되는 블록은 _______ 이다.\n예: try: ... except: ... _______ :', 'finally', 'finally는 예외 발생 여부와 상관없이 항상 실행된다. 자원 정리 코드를 작성한다.', 'python', 1, 'Python에서 try 블록에서 예외가 발생하지 않아도 항상 실행되는 블록은 _______ 이다.\n예: try: ... except: ... _______ :'),
('Python에서 이터레이터와 제너레이터의 차이점은 _______ 이다.\n제너레이터는 yield 키워드를 사용하여 값을 생성한다.', 'yield 사용 여부', '제너레이터는 함수 형태로 값을 하나씩 생성하여 메모리 효율적이다. 큰 데이터 처리에 유용하다.', 'python', 3, 'Python에서 이터레이터와 제너레이터의 차이점은 _______ 이다.\n제너레이터는 yield 키워드를 사용하여 값을 생성한다.'),
('Python에서 클래스 메서드의 첫 번째 매개변수명은 _______ 이다.\n이 매개변수는 클래스自身을 참조한다.', 'cls', 'cls는 클래스 메서드의 첫 번째 매개변수이다. @classmethod 데코레이터와 함께 사용한다. self는 인스턴스를 참조한다.', 'python', 2, 'Python에서 클래스 메서드의 첫 번째 매개변수명은 _______ 이다.\n이 매개변수는 클래스自身을 참조한다.'),
('Python에서 전역 변수를 함수 내에서 수정할 때 사용하는 키워드는 _______ 이다.\n예: _______  count\ncount += 1', 'global', 'global 키워드는 함수 내에서 전역 변수를 참조하고 수정할 수 있게 한다. 사용하지 않으면 지역 변수로 간주된다.', 'python', 2, 'Python에서 전역 변수를 함수 내에서 수정할 때 사용하는 키워드는 _______ 이다.\n예: _______  count\ncount += 1'),
('Python에서 객체의 속성과 메서드를 동적으로 확인하는 함수는 _______ 이다.\n예: _______ (obj)  # 속성 리스트 반환', 'dir', 'dir()은 객체의 속성과 메서드 이름 리스트를 반환한다. introspection에 유용하다.', 'python', 2, 'Python에서 객체의 속성과 메서드를 동적으로 확인하는 함수는 _______ 이다.\n예: _______ (obj)  # 속성 리스트 반환'),
('Python에서 슬라이스로 리스트의 일부분을 추출할 때 사용하는 기호는 _______ 이다.\n예: lst[1:4]  # 인덱스 1~3까지 추출', ':', '슬라이스 [start:stop:step]는 부분 시퀀스를 추출한다. 음수 인덱스는 끝부터 센다.', 'python', 1, 'Python에서 슬라이스로 리스트의 일부분을 추출할 때 사용하는 기호는 _______ 이다.\n예: lst[1:4]  # 인덱스 1~3까지 추출');
